1	// This file provides command-line interface functionality for gh-aw.
2	// This file (logs_metrics.go) contains functions for extracting and analyzing
3	// metrics from workflow execution logs.
4	//
5	// Key responsibilities:
6	//   - Extracting token usage, cost, and turn metrics from logs
7	//   - Identifying missing tools requested by AI agents
8	//   - Detecting MCP (Model Context Protocol) server failures
9	//   - Aggregating metrics across multiple log files
10	//   - Processing structured output from agent execution
11	
12	package cli
13	
14	import (
15		"encoding/json"
16		"errors"
17		"fmt"
18		"os"
19		"path/filepath"
20		"strings"
21	
22		"github.com/github/gh-aw/pkg/console"
23		"github.com/github/gh-aw/pkg/constants"
24		"github.com/github/gh-aw/pkg/fileutil"
25		"github.com/github/gh-aw/pkg/logger"
26		"github.com/github/gh-aw/pkg/workflow"
27	)
28	
29	var logsMetricsLog = logger.New("cli:logs_metrics")
30	
31	// Shared utilities are now in workflow package
32	// extractJSONMetrics is available as an alias
33	var extractJSONMetrics = workflow.ExtractJSONMetrics
34	
35	// extractLogMetrics extracts metrics from downloaded log files
36	// workflowPath is optional and can be provided to help detect GitHub Copilot coding agent runs
37	func extractLogMetrics(logDir string, verbose bool, workflowPath ...string) (LogMetrics, error) {
38		logsMetricsLog.Printf("Extracting log metrics from: %s", logDir)
39		var metrics LogMetrics
40		if verbose {
41			fmt.Fprintln(os.Stderr, console.FormatVerboseMessage("Beginning metric extraction in "+logDir))
42		}
43	
44		// First check if this is a GitHub Copilot coding agent run (not Copilot CLI)
45		var detector *CopilotCodingAgentDetector
46		if len(workflowPath) > 0 && workflowPath[0] != "" {
47			detector = NewCopilotCodingAgentDetectorWithPath(logDir, verbose, workflowPath[0])
48		} else {
49			detector = NewCopilotCodingAgentDetector(logDir, verbose)
50		}
51		isGitHubCopilotCodingAgent := detector.IsGitHubCopilotCodingAgent()
52		logsMetricsLog.Printf("GitHub Copilot coding agent detected: %v", isGitHubCopilotCodingAgent)
53	
54		if isGitHubCopilotCodingAgent && verbose {
55			fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Detected GitHub Copilot coding agent run, using specialized parser"))
56		}
57	
58		// First check for aw_info.json to determine the engine
59		var detectedEngine workflow.CodingAgentEngine
60		infoFilePath := filepath.Join(logDir, "aw_info.json")
61		logsMetricsLog.Printf("Checking for aw_info.json at: %s", infoFilePath)
62		if _, err := os.Stat(infoFilePath); err == nil {
63			logsMetricsLog.Print("Found aw_info.json, extracting engine")
64			// aw_info.json exists, try to extract engine information
65			if engine := extractEngineFromAwInfo(infoFilePath, verbose); engine != nil {
66				detectedEngine = engine
67				logsMetricsLog.Printf("Detected engine: %s", engine.GetID())
68				if verbose {
69					fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Detected engine from aw_info.json: "+engine.GetID()))
70				}
71			} else {
72				logsMetricsLog.Print("Failed to extract engine from aw_info.json")
73				if verbose {
74					fmt.Fprintln(os.Stderr, console.FormatWarningMessage("aw_info.json exists but failed to extract engine"))
75				}
76			}
77		} else {
78			logsMetricsLog.Printf("No aw_info.json found at %s: %v", infoFilePath, err)
79			if verbose {
80				fmt.Fprintln(os.Stderr, console.FormatWarningMessage("No aw_info.json found at "+infoFilePath))
81			}
82		}
83	
84		// Check for safe_output.jsonl artifact file
85		awOutputPath := filepath.Join(logDir, "safe_output.jsonl")
86		if _, err := os.Stat(awOutputPath); err == nil {
87			if verbose {
88				// Report that the agentic output file was found
89				fileInfo, statErr := os.Stat(awOutputPath)
90				if statErr == nil {
91					fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found agentic output file: safe_output.jsonl (%s)", console.FormatFileSize(fileInfo.Size()))))
92				}
93			}
94		}
95	
96		// Check for aw-*.patch and aw-*.bundle artifact files (branch-named patches/bundles)
97		if dirEntries, err := os.ReadDir(logDir); err == nil {
98			for _, entry := range dirEntries {
99				name := entry.Name()
100				isPatch, _ := filepath.Match("aw-*.patch", name)
101				isBundle, _ := filepath.Match("aw-*.bundle", name)
102				if isPatch || isBundle {
103					if verbose {
104						filePath := filepath.Join(logDir, name)
105						if fileInfo, statErr := os.Stat(filePath); statErr == nil {
106							fileType := "git patch"
107							if isBundle {
108								fileType = "git bundle"
109							}
110							fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %s file: %s (%s)", fileType, name, console.FormatFileSize(fileInfo.Size()))))
111						}
112					}
113				}
114			}
115		}
116	
117		// Check for agent_output.json artifact (some workflows may store this under a nested directory)
118		agentOutputPath, agentOutputFound := findAgentOutputFile(logDir)
119		if agentOutputFound {
120			if verbose {
121				fileInfo, statErr := os.Stat(agentOutputPath)
122				if statErr == nil {
123					fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found agent output file: %s (%s)", filepath.Base(agentOutputPath), console.FormatFileSize(fileInfo.Size()))))
124				}
125			}
126			// If the file is not already in the logDir root, copy it for convenience
127			if filepath.Dir(agentOutputPath) != logDir {
128				rootCopy := filepath.Join(logDir, constants.AgentOutputArtifactName)
129				if _, err := os.Stat(rootCopy); errors.Is(err, os.ErrNotExist) {
130					if copyErr := fileutil.CopyFile(agentOutputPath, rootCopy); copyErr == nil && verbose {
131						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Copied agent_output.json to run root for easy access"))
132					}
133				}
134			}
135		}
136	
137		// Try events.jsonl first – it provides a precise, structured event list from the Copilot CLI
138		// session state and is the most reliable source for tool calls, turns, and usage metrics.
139		// Fall back to walking .log files if events.jsonl is not present or cannot be parsed.
140		var err error
141		eventsJSONLParsed := false
142		if eventsJSONLPath := findEventsJSONLFile(logDir); eventsJSONLPath != "" {
143			if verbose {
144				fileInfo, statErr := os.Stat(eventsJSONLPath)
145				if statErr == nil {
146					fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found events.jsonl (%s), using as primary metrics source", console.FormatFileSize(fileInfo.Size()))))
147				} else {
148					fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Found events.jsonl, using as primary metrics source"))
149				}
150			}
151			eventsMetrics, eventsErr := parseEventsJSONLFile(eventsJSONLPath, verbose)
152			if eventsErr == nil {
153				metrics = eventsMetrics
154				eventsJSONLParsed = true
155				logsMetricsLog.Printf("events.jsonl parsed: turns=%d premiumRequests=%d toolCalls=%d",
156					metrics.Turns, metrics.TokenUsage, len(metrics.ToolCalls))
157			} else {
158				logsMetricsLog.Printf("Failed to parse events.jsonl, falling back to log files: %v", eventsErr)
159				if verbose {
160					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse events.jsonl: %v", eventsErr)))
161				}
162			}
163		}
164	
165		// Walk through all .log files when events.jsonl was not available or failed to parse
166		if !eventsJSONLParsed {
167			err = filepath.Walk(logDir, func(path string, info os.FileInfo, err error) error {
168				if err != nil {
169					return err
170				}
171	
172				// Skip directories. workflow-logs/ is explicitly excluded because it contains
173				// GitHub Actions runner captures of each job/step's stdout rather than the agent
174				// artifact data. Parsing those files would double-count token usage and turns;
175				// the same agent session output appears in both the agent artifact
176				// (e.g. agent-stdio.log) and the workflow run logs (workflow-logs/).
177				if info.IsDir() {
178					if info.Name() == "workflow-logs" {
179						logsMetricsLog.Printf("Skipping workflow-logs directory (GHA runner logs, not agent metrics): %s", path)
180						return filepath.SkipDir
181					}
182					return nil
183				}
184	
185				// Process log files - exclude output artifacts like aw_output.txt and agent_output.json
186				fileName := strings.ToLower(info.Name())
187				if (strings.HasSuffix(fileName, ".log") ||
188					(strings.HasSuffix(fileName, ".txt") && strings.Contains(fileName, "log"))) &&
189					!strings.Contains(fileName, "aw_output") &&
190					fileName != constants.AgentOutputFilename {
191	
192					fileMetrics, err := parseLogFileWithEngine(path, detectedEngine, isGitHubCopilotCodingAgent, verbose)
193					if err != nil && verbose {
194						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse log file %s: %v", path, err)))
195						return nil // Continue processing other files
196					}
197	
198					// Aggregate metrics
199					metrics.TokenUsage += fileMetrics.TokenUsage
200					metrics.EstimatedCost += fileMetrics.EstimatedCost
201					if fileMetrics.Turns > metrics.Turns {
202						// For turns, take the maximum rather than summing, since turns represent
203						// the total conversation turns for the entire workflow run
204						metrics.Turns = fileMetrics.Turns
205					}
206	
207					// Aggregate tool sequences and tool calls
208					metrics.ToolSequences = append(metrics.ToolSequences, fileMetrics.ToolSequences...)
209					metrics.ToolCalls = append(metrics.ToolCalls, fileMetrics.ToolCalls...)
210				}
211	
212				return nil
213			})
214		}
215	
216		// Try to parse gateway.jsonl if it exists
217		gatewayMetrics, gatewayErr := parseGatewayLogs(logDir, verbose)
218		if gatewayErr == nil && gatewayMetrics != nil {
219			if verbose {
220				fmt.Fprintln(os.Stderr, console.FormatSuccessMessage("Successfully parsed gateway.jsonl"))
221			}
222			// We've successfully parsed gateway metrics, but we don't add them to the main metrics
223			// structure since they're tracked separately and displayed in their own table
224			logsMetricsLog.Printf("Parsed gateway.jsonl: %d servers, %d requests",
225				len(gatewayMetrics.Servers), gatewayMetrics.TotalRequests)
226		} else if gatewayErr != nil && !strings.Contains(gatewayErr.Error(), "not found") {
227			// Only log if it's an error other than "not found"
228			logsMetricsLog.Printf("Failed to parse gateway.jsonl: %v", gatewayErr)
229			if verbose {
230				fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse gateway.jsonl: %v", gatewayErr)))
231			}
232		}
233	
234		if logsMetricsLog.Enabled() {
235			logsMetricsLog.Printf("Metrics extraction completed: tokens=%d, cost=%.4f, turns=%d",
236				metrics.TokenUsage, metrics.EstimatedCost, metrics.Turns)
237		}
238		return metrics, err
239	}
