257	// extractMissingToolsFromRun extracts missing tool reports from a workflow run's artifacts
258	func extractMissingToolsFromRun(runDir string, run WorkflowRun, verbose bool) ([]MissingToolReport, error) {
259		logsMetricsLog.Printf("Extracting missing tools from run: %d", run.DatabaseID)
260		var missingTools []MissingToolReport
261	
262		// Look for the safe output artifact file that contains structured JSON with items array
263		// This file is created by the collect_ndjson_output.cjs script during workflow execution
264		// After artifact refactoring, the file is flattened to agent_output.json at root
265		agentOutputJSONPath := filepath.Join(runDir, constants.AgentOutputFilename)
266	
267		// Support both new flattened form (agent_output.json) and old forms for backward compatibility:
268		// 1. New: agent_output.json at root (after flattening)
269		// 2. Old: agent-output directory with nested agent-output file
270		// 3. Fallback: search recursively
271		var resolvedAgentOutputFile string
272		if stat, err := os.Stat(agentOutputJSONPath); err == nil && !stat.IsDir() {
273			// New flattened structure: agent_output.json at root
274			resolvedAgentOutputFile = agentOutputJSONPath
275			if verbose {
276				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %s at root: %s", constants.AgentOutputFilename, agentOutputJSONPath)))
277			}
278		} else {
279			// Try old structure: agent-output directory
280			agentOutputPath := filepath.Join(runDir, constants.AgentOutputArtifactName)
281			if stat, err := os.Stat(agentOutputPath); err == nil {
282				if stat.IsDir() {
283					// Directory form – look for nested file
284					nested := filepath.Join(agentOutputPath, constants.AgentOutputArtifactName)
285					if _, nestedErr := os.Stat(nested); nestedErr == nil {
286						resolvedAgentOutputFile = nested
287						if verbose {
288							fmt.Fprintln(os.Stderr, console.FormatInfoMessage("agent_output.json is a directory; using nested file "+nested))
289						}
290					} else if verbose {
291						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("agent_output.json directory present but nested file missing: %v", nestedErr)))
292					}
293				} else {
294					// Regular file
295					resolvedAgentOutputFile = agentOutputPath
296				}
297			} else {
298				// Not present at root – search recursively (depth-first) for a file named agent_output.json
299				if found, ok := findAgentOutputFile(runDir); ok {
300					resolvedAgentOutputFile = found
301					if verbose && found != agentOutputPath {
302						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Found agent_output.json at "+found))
303					}
304				}
305			}
306		}
307	
308		if resolvedAgentOutputFile != "" {
309			// Sanitize the path to prevent path traversal attacks
310			cleanPath := filepath.Clean(resolvedAgentOutputFile)
311	
312			// Read the safe output artifact file
313			content, readErr := os.ReadFile(cleanPath)
314			if readErr != nil {
315				if verbose {
316					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to read safe output file %s: %v", cleanPath, readErr)))
317				}
318				return missingTools, nil // Continue processing without this file
319			}
320	
321			// Parse the structured JSON output from the collect script
322			var safeOutput struct {
323				Items  []json.RawMessage `json:"items"`
324				Errors []string          `json:"errors,omitempty"`
325			}
326	
327			if err := json.Unmarshal(content, &safeOutput); err != nil {
328				if verbose {
329					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse safe output JSON from %s: %v", cleanPath, err)))
330				}
331				return missingTools, nil // Continue processing without this file
332			}
333	
334			// Extract missing-tool entries from the items array
335			for _, itemRaw := range safeOutput.Items {
336				var item struct {
337					Type         string `json:"type"`
338					Tool         string `json:"tool,omitempty"`
339					Reason       string `json:"reason,omitempty"`
340					Alternatives string `json:"alternatives,omitempty"`
341					Timestamp    string `json:"timestamp,omitempty"`
342				}
343	
344				if err := json.Unmarshal(itemRaw, &item); err != nil {
345					if verbose {
346						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse item from safe output: %v", err)))
347					}
348					continue // Skip malformed items
349				}
350	
351				// Check if this is a missing-tool entry
352				if item.Type == "missing_tool" {
353					missingTool := MissingToolReport{
354						Tool:         item.Tool,
355						Reason:       item.Reason,
356						Alternatives: item.Alternatives,
357						Timestamp:    item.Timestamp,
358						WorkflowName: run.WorkflowName,
359						RunID:        run.DatabaseID,
360					}
361					missingTools = append(missingTools, missingTool)
362	
363					if verbose {
364						fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found missing_tool entry: %s (%s)", item.Tool, item.Reason)))
365					}
366				}
367			}
368	
369			if verbose && len(missingTools) > 0 {
370				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %d missing tool reports in safe output artifact for run %d", len(missingTools), run.DatabaseID)))
371			}
372			logsMetricsLog.Printf("Found %d missing tool reports", len(missingTools))
373		} else {
374			logsMetricsLog.Print("No safe output artifact found")
375			if verbose {
376				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("No safe output artifact found at %s for run %d", agentOutputJSONPath, run.DatabaseID)))
377			}
378		}
379	
380		return missingTools, nil
381	}
