633	// extractMCPFailuresFromRun extracts MCP server failure reports from a workflow run's logs
634	func extractMCPFailuresFromRun(runDir string, run WorkflowRun, verbose bool) ([]MCPFailureReport, error) {
635		logsMetricsLog.Printf("Extracting MCP failures from run: %d", run.DatabaseID)
636		var mcpFailures []MCPFailureReport
637	
638		// Look for agent output logs that contain the system init entry with MCP server status
639		// This information is available in the raw log files, typically with names containing "log"
640		err := filepath.Walk(runDir, func(path string, info os.FileInfo, err error) error {
641			if err != nil {
642				return err
643			}
644	
645			// Skip directories
646			if info.IsDir() {
647				return nil
648			}
649	
650			// Process log files - exclude output artifacts
651			fileName := strings.ToLower(info.Name())
652			if (strings.HasSuffix(fileName, ".log") ||
653				(strings.HasSuffix(fileName, ".txt") && strings.Contains(fileName, "log"))) &&
654				!strings.Contains(fileName, "aw_output") &&
655				!strings.Contains(fileName, "agent_output") &&
656				!strings.Contains(fileName, "access") {
657	
658				failures, parseErr := extractMCPFailuresFromLogFile(path, run, verbose)
659				if parseErr != nil {
660					if verbose {
661						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse MCP failures from %s: %v", filepath.Base(path), parseErr)))
662					}
663					return nil // Continue processing other files
664				}
665				mcpFailures = append(mcpFailures, failures...)
666			}
667	
668			return nil
669		})
670	
671		if err != nil {
672			return mcpFailures, fmt.Errorf("error walking run directory: %w", err)
673		}
674	
675		if verbose && len(mcpFailures) > 0 {
676			fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %d MCP server failures for run %d", len(mcpFailures), run.DatabaseID)))
677		}
678		logsMetricsLog.Printf("Found %d MCP failures", len(mcpFailures))
679	
680		return mcpFailures, nil
681	}
682	
683	// extractMCPFailuresFromLogFile parses a single log file for MCP server failures
684	func extractMCPFailuresFromLogFile(logPath string, run WorkflowRun, verbose bool) ([]MCPFailureReport, error) {
685		var mcpFailures []MCPFailureReport
686	
687		content, err := os.ReadFile(logPath)
688		if err != nil {
689			return mcpFailures, fmt.Errorf("error reading log file: %w", err)
690		}
691	
692		logContent := string(content)
693	
694		// First try to parse as JSON array
695		var logEntries []map[string]any
696		if err := json.Unmarshal(content, &logEntries); err == nil {
697			// Successfully parsed as JSON array, process entries
698			for _, entry := range logEntries {
699				if entryType, ok := entry["type"].(string); ok && entryType == "system" {
700					if subtype, ok := entry["subtype"].(string); ok && subtype == "init" {
701						if mcpServers, ok := entry["mcp_servers"].([]any); ok {
702							for _, serverInterface := range mcpServers {
703								if server, ok := serverInterface.(map[string]any); ok {
704									serverName, hasName := server["name"].(string)
705									status, hasStatus := server["status"].(string)
706	
707									if hasName && hasStatus && status == "failed" {
708										failure := MCPFailureReport{
709											ServerName:   serverName,
710											Status:       status,
711											WorkflowName: run.WorkflowName,
712											RunID:        run.DatabaseID,
713										}
714	
715										// Try to extract timestamp if available
716										if timestamp, hasTimestamp := entry["timestamp"].(string); hasTimestamp {
717											failure.Timestamp = timestamp
718										}
719	
720										mcpFailures = append(mcpFailures, failure)
721	
722										if verbose {
723											fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Found MCP server failure: %s (status: %s)", serverName, status)))
724										}
725									}
726								}
727							}
728						}
729					}
730				}
731			}
732		} else {
733			// Fallback: Try to parse as JSON lines (Claude logs are typically NDJSON format)
734			lines := strings.SplitSeq(logContent, "\n")
735			for line := range lines {
736				line = strings.TrimSpace(line)
737				if line == "" || !strings.HasPrefix(line, "{") {
738					continue
739				}
740	
741				// Try to parse each line as JSON
742				var entry map[string]any
743				if err := json.Unmarshal([]byte(line), &entry); err != nil {
744					continue // Skip non-JSON lines
745				}
746	
747				// Look for system init entries that contain MCP server information
748				if entryType, ok := entry["type"].(string); ok && entryType == "system" {
749					if subtype, ok := entry["subtype"].(string); ok && subtype == "init" {
750						if mcpServers, ok := entry["mcp_servers"].([]any); ok {
751							for _, serverInterface := range mcpServers {
752								if server, ok := serverInterface.(map[string]any); ok {
753									serverName, hasName := server["name"].(string)
754									status, hasStatus := server["status"].(string)
755	
756									if hasName && hasStatus && status == "failed" {
757										failure := MCPFailureReport{
758											ServerName:   serverName,
759											Status:       status,
760											WorkflowName: run.WorkflowName,
761											RunID:        run.DatabaseID,
762										}
763	
764										// Try to extract timestamp if available
765										if timestamp, hasTimestamp := entry["timestamp"].(string); hasTimestamp {
766											failure.Timestamp = timestamp
767										}
768	
769										mcpFailures = append(mcpFailures, failure)
770	
771										if verbose {
772											fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Found MCP server failure: %s (status: %s)", serverName, status)))
773										}
774									}
775								}
776							}
777						}
778					}
779				}
780			}
781		}
782	
783		return mcpFailures, nil
784	}
