package cli

import (
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"strings"

	"github.com/github/gh-aw/pkg/console"
	"github.com/github/gh-aw/pkg/logger"
)

var copilotCodingAgentLog = logger.New("cli:copilot_agent")

// agentLogPatterns contains patterns that indicate GitHub Copilot coding agent (not Copilot CLI)
var agentLogPatterns = []*regexp.Regexp{
	regexp.MustCompile(`(?i)github.*copilot.*agent`),
	regexp.MustCompile(`(?i)copilot-swe-agent`),
	regexp.MustCompile(`(?i)@github/copilot-swe-agent`),
	regexp.MustCompile(`(?i)agent.*task.*execution`),
	regexp.MustCompile(`(?i)copilot.*agent.*v\d+\.\d+`),
}

// CopilotCodingAgentDetector contains heuristics to detect if a workflow run was executed by GitHub Copilot coding agent
type CopilotCodingAgentDetector struct {
	runDir       string
	verbose      bool
	workflowPath string // Optional: workflow file path from GitHub API (e.g., .github/workflows/copilot-swe-agent.yml)
}

// NewCopilotCodingAgentDetector creates a new detector for GitHub Copilot coding agent runs
func NewCopilotCodingAgentDetector(runDir string, verbose bool) *CopilotCodingAgentDetector {
	return &CopilotCodingAgentDetector{
		runDir:  runDir,
		verbose: verbose,
	}
}

// NewCopilotCodingAgentDetectorWithPath creates a detector with workflow path hint
func NewCopilotCodingAgentDetectorWithPath(runDir string, verbose bool, workflowPath string) *CopilotCodingAgentDetector {
	return &CopilotCodingAgentDetector{
		runDir:       runDir,
		verbose:      verbose,
		workflowPath: workflowPath,
	}
}

// IsGitHubCopilotCodingAgent uses heuristics to determine if this run was executed by GitHub Copilot coding agent
// (not the Copilot CLI engine or agentic workflows)
func (d *CopilotCodingAgentDetector) IsGitHubCopilotCodingAgent() bool {
	copilotCodingAgentLog.Printf("Detecting if run is GitHub Copilot coding agent: %s", d.runDir)

	// If aw_info.json exists, this is an agentic workflow, NOT a GitHub Copilot coding agent run
	awInfoPath := filepath.Join(d.runDir, "aw_info.json")
	if _, err := os.Stat(awInfoPath); err == nil {
		copilotCodingAgentLog.Print("Found aw_info.json - this is an agentic workflow, not a GitHub Copilot coding agent")
		return false
	}

	// Heuristic 1: Check workflow path if provided (most reliable hint from GitHub API)
	if d.hasAgentWorkflowPath() {
		copilotCodingAgentLog.Print("Detected copilot-swe-agent in workflow path")
		return true
	}

	// Heuristic 2: Check for agent-specific log patterns
	if d.hasAgentLogPatterns() {
		copilotCodingAgentLog.Print("Detected agent log patterns")
		return true
	}

	// Heuristic 3: Check for agent-specific artifacts
	if d.hasAgentArtifacts() {
		copilotCodingAgentLog.Print("Detected agent artifacts")
		return true
	}

	copilotCodingAgentLog.Print("No GitHub Copilot coding agent indicators found")
	return false
}

// hasAgentWorkflowPath checks if the workflow path indicates a Copilot coding agent run
// The workflow ID is always "copilot-swe-agent" for GitHub Copilot coding agent runs
func (d *CopilotCodingAgentDetector) hasAgentWorkflowPath() bool {
	if d.workflowPath == "" {
		return false
	}

	// Extract the workflow filename from the path
	// E.g., .github/workflows/copilot-swe-agent.yml -> copilot-swe-agent
	filename := filepath.Base(d.workflowPath)
	workflowID := strings.TrimSuffix(filename, filepath.Ext(filename))

	// GitHub Copilot coding agent runs always use "copilot-swe-agent" as the workflow ID
	if workflowID == "copilot-swe-agent" {
		if d.verbose {
			fmt.Fprintln(os.Stderr, console.FormatInfoMessage(
				fmt.Sprintf("Detected GitHub Copilot coding agent from workflow path: %s (ID: %s)", d.workflowPath, workflowID)))
		}
		return true
	}

	return false
}

// hasAgentLogPatterns checks log files for patterns specific to GitHub Copilot coding agent
func (d *CopilotCodingAgentDetector) hasAgentLogPatterns() bool {
	found := false
	// Check log files for agent-specific patterns
	_ = filepath.Walk(d.runDir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info == nil || info.IsDir() {
			return nil
		}

		fileName := strings.ToLower(info.Name())
		if strings.HasSuffix(fileName, ".log") || strings.HasSuffix(fileName, ".txt") {
			// Read first 10KB of log file to check patterns
			content, err := readLogHeader(path, 10240)
			if err != nil {
				return nil
			}

			for _, pattern := range agentLogPatterns {
				if pattern.MatchString(content) {
					if d.verbose {
						fmt.Fprintln(os.Stderr, console.FormatInfoMessage(
							fmt.Sprintf("Found agent pattern in %s: %s", filepath.Base(path), pattern.String())))
					}
					found = true
					return filepath.SkipAll // Stop walking, we found a match
				}
			}
		}

		return nil
	})

	return found
}

// hasAgentArtifacts checks for artifacts specific to GitHub Copilot coding agent runs
func (d *CopilotCodingAgentDetector) hasAgentArtifacts() bool {
	// Check for agent-specific artifact patterns
	agentArtifacts := []string{
		"copilot-agent-output",
		"agent-session-result",
		"copilot-swe-agent-output",
	}

	for _, artifactName := range agentArtifacts {
		artifactPath := filepath.Join(d.runDir, artifactName)
		if _, err := os.Stat(artifactPath); err == nil {
			if d.verbose {
				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(
					"Found agent artifact: "+artifactName))
			}
			return true
		}
	}

	return false
}

// readLogHeader reads the first maxBytes from a log file
func readLogHeader(path string, maxBytes int) (string, error) {
	file, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer file.Close()

	buffer := make([]byte, maxBytes)
	n, err := file.Read(buffer)
	if err != nil && n == 0 {
		return "", err
	}

	return string(buffer[:n]), nil
}

// This file provides command-line interface functionality for gh-aw.
// This file (copilot_events_jsonl.go) contains functions for finding and
// parsing Copilot CLI events.jsonl files from session-state artifacts.
//
// Key responsibilities:
//   - Locating events.jsonl in the copilot-session-state artifact directory
//   - Parsing the structured event log to extract tool calls, turns, and usage
//   - Providing precise, structured metrics as the primary data source for
//     Copilot CLI log analysis (before falling back to debug log parsing)

package cli

import (
	"bufio"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/github/gh-aw/pkg/console"
	"github.com/github/gh-aw/pkg/logger"
	"github.com/github/gh-aw/pkg/stats"
	"github.com/github/gh-aw/pkg/workflow"
)

var copilotEventsJSONLLog = logger.New("cli:copilot_events_jsonl")

// copilotEventsJSONLEntry represents a single event in a Copilot events.jsonl file.
// All events share the same envelope: type, id, timestamp, and a type-specific data object.
//
// The events.jsonl file is written by the Copilot CLI to:
//
//	~/.copilot/session-state/<session-uuid>/events.jsonl
//
// After artifact upload/download it is located at:
//
//	<logDir>/sandbox/agent/logs/copilot-session-state/<uuid>/events.jsonl
type copilotEventsJSONLEntry struct {
	Type      string                      `json:"type"`
	ID        string                      `json:"id"`
	Timestamp string                      `json:"timestamp"`
	ParentID  string                      `json:"parentId,omitempty"`
	Data      copilotEventsJSONLEntryData `json:"data"`
}

// copilotEventsJSONLEntryData holds the type-specific payload for each event.
// Fields are populated only for the relevant event types.
type copilotEventsJSONLEntryData struct {
	// session.start fields
	SessionID      string `json:"sessionId,omitempty"`
	CopilotVersion string `json:"copilotVersion,omitempty"`

	// session.model_change fields
	NewModel string `json:"newModel,omitempty"`

	// tool.execution_start fields
	ToolCallID    string `json:"toolCallId,omitempty"`
	ToolName      string `json:"toolName,omitempty"`
	MCPServerName string `json:"mcpServerName,omitempty"`
	MCPToolName   string `json:"mcpToolName,omitempty"`

	// tool.execution_complete fields
	Success bool   `json:"success"`
	Model   string `json:"model,omitempty"`

	// session.shutdown fields
	ShutdownType         string                          `json:"shutdownType,omitempty"`
	TotalPremiumRequests int                             `json:"totalPremiumRequests,omitempty"`
	ModelMetrics         map[string]*copilotModelMetrics `json:"modelMetrics,omitempty"`
}

// copilotModelMetrics holds per-model usage statistics from the session.shutdown event.
type copilotModelMetrics struct {
	Requests *copilotRequestMetrics `json:"requests,omitempty"`
	Usage    *copilotUsageMetrics   `json:"usage,omitempty"`
}

// copilotRequestMetrics holds request count and cost for a model.
type copilotRequestMetrics struct {
	Count int `json:"count"`
	Cost  int `json:"cost"`
}

// copilotUsageMetrics holds token usage for a model.
type copilotUsageMetrics struct {
	InputTokens      int `json:"inputTokens"`
	OutputTokens     int `json:"outputTokens"`
	CacheReadTokens  int `json:"cacheReadTokens"`
	CacheWriteTokens int `json:"cacheWriteTokens"`
}

// findEventsJSONLFile searches for an events.jsonl file in logDir.
// It first checks the canonical location at
// sandbox/agent/logs/copilot-session-state/<uuid>/events.jsonl
// and then falls back to a full recursive walk of logDir.
// Returns the first path found, or an empty string if not found.
func findEventsJSONLFile(logDir string) string {
	copilotEventsJSONLLog.Printf("Searching for events.jsonl in: %s", logDir)

	// Try the canonical location first (avoids a full directory walk in the common case)
	sessionStateDir := filepath.Join(logDir, "sandbox", "agent", "logs", "copilot-session-state")
	if canonicalPath := findFileInDir(sessionStateDir, "events.jsonl"); canonicalPath != "" {
		copilotEventsJSONLLog.Printf("Found events.jsonl at canonical location: %s", canonicalPath)
		return canonicalPath
	}

	// Fall back to a recursive search of the full log directory
	var foundPath string
	_ = filepath.Walk(logDir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info == nil {
			return nil
		}
		if !info.IsDir() && info.Name() == "events.jsonl" && foundPath == "" {
			foundPath = path
			return errors.New("stop") // sentinel to stop walking
		}
		return nil
	})

	if foundPath != "" {
		copilotEventsJSONLLog.Printf("Found events.jsonl via recursive search: %s", foundPath)
	} else {
		copilotEventsJSONLLog.Printf("events.jsonl not found in: %s", logDir)
	}
	return foundPath
}

// findFileInDir searches for a file by name within dir (recursively).
// Returns the first matching path, or empty string if not found.
func findFileInDir(dir, name string) string {
	var found string
	_ = filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info == nil {
			return nil
		}
		if !info.IsDir() && info.Name() == name && found == "" {
			found = path
			return errors.New("stop")
		}
		return nil
	})
	return found
}

// parseEventsJSONLFile parses a Copilot events.jsonl file and extracts log metrics.
//
// events.jsonl provides precise, structured data about a Copilot CLI session:
//   - "session.start":          session metadata (sessionId, copilotVersion)
//   - "user.message":           one per conversation turn (used to count turns)
//   - "tool.execution_start":   a tool invocation (data.toolName)
//   - "tool.execution_complete": completion of a tool call
//   - "session.shutdown":       session summary (totalPremiumRequests, modelMetrics)
//
// Returns the extracted metrics and nil on success, or empty metrics and an
// error if the file cannot be read or contains no recognizable events.
func parseEventsJSONLFile(path string, verbose bool) (workflow.LogMetrics, error) {
	copilotEventsJSONLLog.Printf("Parsing events.jsonl from: %s", path)

	var metrics workflow.LogMetrics

	// Sanitize path to prevent traversal
	cleanPath := filepath.Clean(path)

	file, err := os.Open(cleanPath)
	if err != nil {
		return metrics, fmt.Errorf("failed to open events.jsonl: %w", err)
	}
	defer file.Close()

	toolCallMap := make(map[string]*workflow.ToolCallInfo)
	var currentSequence []string
	turns := 0
	totalTokens := 0
	foundAnyEvent := false

	// Per-turn timestamps used to compute Time Between Turns (TBT)
	var turnTimestamps []time.Time

	scanner := bufio.NewScanner(file)
	buf := make([]byte, maxScannerBufferSize)
	scanner.Buffer(buf, maxScannerBufferSize)

	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" || !strings.HasPrefix(line, "{") {
			continue
		}

		var entry copilotEventsJSONLEntry
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			copilotEventsJSONLLog.Printf("Skipping malformed events.jsonl line: %v", err)
			continue
		}

		foundAnyEvent = true

		switch entry.Type {
		case "session.start":
			copilotEventsJSONLLog.Printf("session.start: sessionId=%s copilotVersion=%s",
				entry.Data.SessionID, entry.Data.CopilotVersion)

		case "user.message":
			// Each user message represents one conversation turn.
			// Save the current tool sequence before starting a new turn.
			turns++
			if len(currentSequence) > 0 {
				metrics.ToolSequences = append(metrics.ToolSequences, currentSequence)
				currentSequence = []string{}
			}
			// Record the timestamp for TBT computation.
			if entry.Timestamp != "" {
				if ts, parseErr := time.Parse(time.RFC3339Nano, entry.Timestamp); parseErr == nil {
					turnTimestamps = append(turnTimestamps, ts)
				} else if ts, parseErr = time.Parse(time.RFC3339, entry.Timestamp); parseErr == nil {
					turnTimestamps = append(turnTimestamps, ts)
				}
			}
			copilotEventsJSONLLog.Printf("user.message: turn=%d", turns)

		case "tool.execution_start":
			// Record the tool invocation and add to the current turn's sequence.
			toolName := entry.Data.ToolName
			if toolName != "" {
				currentSequence = append(currentSequence, toolName)
				if toolInfo, exists := toolCallMap[toolName]; exists {
					toolInfo.CallCount++
				} else {
					toolCallMap[toolName] = &workflow.ToolCallInfo{
						Name:      toolName,
						CallCount: 1,
					}
				}
				copilotEventsJSONLLog.Printf("tool.execution_start: %s", toolName)
			}

		case "session.shutdown":
			// Aggregate token usage across all models from modelMetrics.
			// modelMetrics provides the most accurate token counts; fall back to
			// totalPremiumRequests only when modelMetrics is absent.
			for model, m := range entry.Data.ModelMetrics {
				if m.Usage != nil {
					modelTokens := m.Usage.InputTokens + m.Usage.OutputTokens
					totalTokens += modelTokens
					copilotEventsJSONLLog.Printf("session.shutdown: model=%s inputTokens=%d outputTokens=%d",
						model, m.Usage.InputTokens, m.Usage.OutputTokens)
				}
			}
			if totalTokens == 0 && entry.Data.TotalPremiumRequests > 0 {
				// Fallback: use premium requests as a proxy when token counts are unavailable
				totalTokens = entry.Data.TotalPremiumRequests
				copilotEventsJSONLLog.Printf("session.shutdown: using totalPremiumRequests=%d as token proxy",
					entry.Data.TotalPremiumRequests)
			}
			copilotEventsJSONLLog.Printf("session.shutdown: type=%s totalPremiumRequests=%d totalTokens=%d",
				entry.Data.ShutdownType, entry.Data.TotalPremiumRequests, totalTokens)
		}
	}

	if scanErr := scanner.Err(); scanErr != nil {
		return metrics, fmt.Errorf("error reading events.jsonl: %w", scanErr)
	}

	if !foundAnyEvent {
		return metrics, errors.New("no events found in events.jsonl")
	}

	// Flush any remaining tool sequence
	if len(currentSequence) > 0 {
		metrics.ToolSequences = append(metrics.ToolSequences, currentSequence)
	}

	// Convert tool call map to slice
	for _, toolInfo := range toolCallMap {
		metrics.ToolCalls = append(metrics.ToolCalls, *toolInfo)
	}

	metrics.TokenUsage = totalTokens
	metrics.Turns = turns

	// Compute Time Between Turns (TBT) from per-turn timestamps.
	// TBT[i] = timestamp[i] - timestamp[i-1] for i > 0. Two or more timestamps
	// are required to measure at least one interval. Only positive intervals are
	// included so that identical or out-of-order timestamps don't skew the statistics.
	if len(turnTimestamps) >= 2 {
		var tbtStats stats.StatVar
		for i := 1; i < len(turnTimestamps); i++ {
			tbt := turnTimestamps[i].Sub(turnTimestamps[i-1])
			if tbt > 0 {
				tbtStats.Add(float64(tbt))
			}
		}
		if tbtStats.Count() > 0 {
			metrics.AvgTimeBetweenTurns = time.Duration(tbtStats.Mean())
			metrics.MaxTimeBetweenTurns = time.Duration(tbtStats.Max())
			metrics.MedianTimeBetweenTurns = time.Duration(tbtStats.Median())
			metrics.StdDevTimeBetweenTurns = time.Duration(tbtStats.SampleStdDev())
			copilotEventsJSONLLog.Printf("TBT computed: avg=%s max=%s median=%s stddev=%s intervals=%d",
				metrics.AvgTimeBetweenTurns, metrics.MaxTimeBetweenTurns,
				metrics.MedianTimeBetweenTurns, metrics.StdDevTimeBetweenTurns, tbtStats.Count())
		}
	}

	copilotEventsJSONLLog.Printf("Parsed events.jsonl: turns=%d totalTokens=%d toolCalls=%d sequences=%d",
		turns, totalTokens, len(toolCallMap), len(metrics.ToolSequences))

	if verbose {
		fmt.Fprintln(os.Stderr, console.FormatSuccessMessage(
			fmt.Sprintf("Parsed events.jsonl: %d turns, %d tokens, %d tool calls",
				turns, totalTokens, len(toolCallMap))))
	}

	return metrics, nil
}

//go:build !integration

package cli

import (
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestFindEventsJSONLFile verifies that findEventsJSONLFile can locate an events.jsonl
// file both at the canonical copilot-session-state path and via recursive search.
func TestFindEventsJSONLFile(t *testing.T) {
	tests := []struct {
		name           string
		setupFunc      func(string) error
		expectFound    bool
		expectContains string // substring the found path must contain (optional)
	}{
		{
			name: "finds events.jsonl at canonical session-state path",
			setupFunc: func(dir string) error {
				sessionDir := filepath.Join(dir, "sandbox", "agent", "logs",
					"copilot-session-state", "be25adf7-5860-40ac-bfb6-2eb178a0f848")
				if err := os.MkdirAll(sessionDir, 0755); err != nil {
					return err
				}
				return os.WriteFile(filepath.Join(sessionDir, "events.jsonl"), []byte("{}"), 0644)
			},
			expectFound:    true,
			expectContains: "events.jsonl",
		},
		{
			name: "finds events.jsonl via recursive fallback",
			setupFunc: func(dir string) error {
				nestedDir := filepath.Join(dir, "some", "nested", "dir")
				if err := os.MkdirAll(nestedDir, 0755); err != nil {
					return err
				}
				return os.WriteFile(filepath.Join(nestedDir, "events.jsonl"), []byte("{}"), 0644)
			},
			expectFound:    true,
			expectContains: "events.jsonl",
		},
		{
			name: "returns empty string when events.jsonl is absent",
			setupFunc: func(dir string) error {
				return os.WriteFile(filepath.Join(dir, "other.log"), []byte("log content"), 0644)
			},
			expectFound: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			dir := t.TempDir()
			require.NoError(t, tt.setupFunc(dir), "setup should succeed")

			result := findEventsJSONLFile(dir)
			if tt.expectFound {
				assert.NotEmpty(t, result, "should find events.jsonl")
				if tt.expectContains != "" {
					assert.Contains(t, result, tt.expectContains, "path should contain expected substring")
				}
			} else {
				assert.Empty(t, result, "should not find events.jsonl")
			}
		})
	}
}

// realFormatEventsLine builds an events.jsonl line using the actual Copilot CLI format:
// each event has a top-level type, a nested data object, an id, and a timestamp.
func realFormatEventsLine(eventType string, dataJSON string) string {
	return `{"type":"` + eventType + `","data":` + dataJSON + `,"id":"test-id","timestamp":"2026-04-02T04:00:00.000Z"}`
}

// TestParseEventsJSONLFile verifies that parseEventsJSONLFile correctly extracts
// turns, tool calls, tool sequences, and token counts from events.jsonl using
// the real Copilot CLI format (nested data object, tool.execution_start events).
func TestParseEventsJSONLFile(t *testing.T) {
	tests := []struct {
		name          string
		content       string
		wantTurns     int
		wantToolCalls []string // tool names that must appear in ToolCalls
		wantTokens    int      // expected TokenUsage
		wantSequences int      // number of tool sequences expected
		wantErr       bool
	}{
		{
			name: "full session with real format",
			content: realFormatEventsLine("session.start", `{"sessionId":"accf8264","copilotVersion":"1.0.15"}`) + "\n" +
				realFormatEventsLine("session.model_change", `{"newModel":"claude-sonnet-4.6"}`) + "\n" +
				realFormatEventsLine("user.message", `{"content":"Do the task","agentMode":"autopilot"}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc1","toolName":"bash","arguments":{"command":"ls"}}`) + "\n" +
				realFormatEventsLine("tool.execution_complete", `{"toolCallId":"tc1","success":true,"model":"claude-sonnet-4.6"}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc2","toolName":"read_file","arguments":{"path":"main.go"}}`) + "\n" +
				realFormatEventsLine("tool.execution_complete", `{"toolCallId":"tc2","success":true,"model":"claude-sonnet-4.6"}`) + "\n" +
				realFormatEventsLine("user.message", `{"content":"Now verify","agentMode":"autopilot"}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc3","toolName":"bash","arguments":{"command":"go test"}}`) + "\n" +
				realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":2,"modelMetrics":{"claude-sonnet-4.6":{"requests":{"count":14,"cost":2},"usage":{"inputTokens":799195,"outputTokens":6148,"cacheReadTokens":721116,"cacheWriteTokens":0}}}}`) + "\n",
			wantTurns:     2,
			wantToolCalls: []string{"bash", "read_file"},
			wantTokens:    805343, // 799195 + 6148
			wantSequences: 2,
		},
		{
			name: "session with one turn and shutdown with modelMetrics",
			content: realFormatEventsLine("user.message", `{"content":"Do something"}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc1","toolName":"mcpscripts-gh","arguments":{}}`) + "\n" +
				realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":3,"modelMetrics":{"claude-haiku-4.5":{"requests":{"count":1,"cost":0},"usage":{"inputTokens":5442,"outputTokens":457,"cacheReadTokens":0,"cacheWriteTokens":0}}}}`) + "\n",
			wantTurns:     1,
			wantToolCalls: []string{"mcpscripts-gh"},
			wantTokens:    5899, // 5442 + 457
			wantSequences: 1,
		},
		{
			name: "shutdown falls back to totalPremiumRequests when modelMetrics absent",
			content: realFormatEventsLine("user.message", `{"content":"Hello"}`) + "\n" +
				realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":5}`) + "\n",
			wantTurns:  1,
			wantTokens: 5, // falls back to totalPremiumRequests
		},
		{
			name: "repeated tool calls aggregated by name",
			content: realFormatEventsLine("user.message", `{"content":"Run tests"}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc1","toolName":"bash","arguments":{}}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc2","toolName":"bash","arguments":{}}`) + "\n" +
				realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":1,"modelMetrics":{"m":{"usage":{"inputTokens":100,"outputTokens":10}}}}`) + "\n",
			wantTurns:     1,
			wantToolCalls: []string{"bash"},
			wantTokens:    110,
			wantSequences: 1,
		},
		{
			name:    "empty file returns error",
			content: "",
			wantErr: true,
		},
		{
			name:    "file with no recognizable events returns error",
			content: "not json at all\njust plain text\n",
			wantErr: true,
		},
		{
			name: "malformed lines are skipped gracefully",
			content: realFormatEventsLine("user.message", `{"content":"Hello"}`) + "\n" +
				"{invalid json}\n" +
				realFormatEventsLine("session.shutdown", `{"totalPremiumRequests":2,"modelMetrics":{"m":{"usage":{"inputTokens":100,"outputTokens":20}}}}`) + "\n",
			wantTurns:  1,
			wantTokens: 120,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			dir := t.TempDir()
			eventsPath := filepath.Join(dir, "events.jsonl")
			require.NoError(t, os.WriteFile(eventsPath, []byte(tt.content), 0644))

			metrics, err := parseEventsJSONLFile(eventsPath, false)

			if tt.wantErr {
				assert.Error(t, err, "expected an error")
				return
			}

			require.NoError(t, err, "should parse without error")
			assert.Equal(t, tt.wantTurns, metrics.Turns, "turns should match")
			assert.Equal(t, tt.wantTokens, metrics.TokenUsage, "token usage should match")

			if tt.wantSequences > 0 {
				assert.Len(t, metrics.ToolSequences, tt.wantSequences, "tool sequence count should match")
			}

			// Verify each expected tool name appears in ToolCalls
			toolNames := make(map[string]bool)
			for _, tc := range metrics.ToolCalls {
				toolNames[tc.Name] = true
			}
			for _, expectedTool := range tt.wantToolCalls {
				assert.True(t, toolNames[expectedTool], "tool %q should be in ToolCalls", expectedTool)
			}
		})
	}
}

// TestParseEventsJSONLFile_RealArtifact validates the parser against known metrics
// from the actual artifact in run 23883588837 (accf8264 session).
// Expected: 2 turns, 811242 total tokens (799195+6148 from claude-sonnet + 5442+457 from claude-haiku).
func TestParseEventsJSONLFile_RealArtifact(t *testing.T) {
	content := realFormatEventsLine("session.start", `{"sessionId":"accf8264","copilotVersion":"1.0.15"}`) + "\n" +
		realFormatEventsLine("user.message", `{"content":"task prompt"}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t1","toolName":"report_intent","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t2","toolName":"github-list_pull_requests","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t3","toolName":"mcpscripts-gh","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t4","toolName":"web_fetch","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t5","toolName":"bash","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t6","toolName":"mcpscripts-github_discussion_query","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t7","toolName":"playwright-browser_navigate","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t8","toolName":"task","arguments":{}}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t9","toolName":"safeoutputs-add_comment","arguments":{}}`) + "\n" +
		realFormatEventsLine("user.message", `{"content":"second turn"}`) + "\n" +
		realFormatEventsLine("tool.execution_start", `{"toolCallId":"t10","toolName":"bash","arguments":{}}`) + "\n" +
		realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":2,"modelMetrics":{"claude-sonnet-4.6":{"requests":{"count":14,"cost":2},"usage":{"inputTokens":799195,"outputTokens":6148,"cacheReadTokens":721116,"cacheWriteTokens":0}},"claude-haiku-4.5":{"requests":{"count":1,"cost":0},"usage":{"inputTokens":5442,"outputTokens":457,"cacheReadTokens":0,"cacheWriteTokens":0}}}}`) + "\n"

	dir := t.TempDir()
	eventsPath := filepath.Join(dir, "events.jsonl")
	require.NoError(t, os.WriteFile(eventsPath, []byte(content), 0644))

	metrics, err := parseEventsJSONLFile(eventsPath, false)
	require.NoError(t, err, "should parse without error")

	assert.Equal(t, 2, metrics.Turns, "should detect 2 turns")
	// (799195+6148) + (5442+457) = 805343 + 5899 = 811242
	assert.Equal(t, 811242, metrics.TokenUsage, "should sum tokens from both models")

	// Should have 2 sequences (one per user.message)
	assert.Len(t, metrics.ToolSequences, 2, "should have 2 tool sequences")

	// bash appears in both turns
	toolCounts := make(map[string]int)
	for _, tc := range metrics.ToolCalls {
		toolCounts[tc.Name] = tc.CallCount
	}
	assert.Equal(t, 2, toolCounts["bash"], "bash should be called twice (once per turn)")
	assert.Equal(t, 1, toolCounts["report_intent"], "report_intent called once")
}

// TestExtractLogMetrics_EventsJSONLPriority verifies that extractLogMetrics uses
// events.jsonl as the primary source when it is present, and falls back to log
// file parsing when it is absent.
func TestExtractLogMetrics_EventsJSONLPriority(t *testing.T) {
	t.Run("uses events.jsonl when present", func(t *testing.T) {
		dir := t.TempDir()

		// Write aw_info.json so the engine is detected
		require.NoError(t, os.WriteFile(filepath.Join(dir, "aw_info.json"),
			[]byte(`{"engine_id":"copilot"}`), 0644))

		// Create events.jsonl in the canonical location
		sessionDir := filepath.Join(dir, "sandbox", "agent", "logs",
			"copilot-session-state", "session-uuid-123")
		require.NoError(t, os.MkdirAll(sessionDir, 0755))
		eventsContent :=
			realFormatEventsLine("session.start", `{"sessionId":"s1","copilotVersion":"1.0.0"}`) + "\n" +
				realFormatEventsLine("user.message", `{"content":"Do something"}`) + "\n" +
				realFormatEventsLine("tool.execution_start", `{"toolCallId":"tc1","toolName":"bash","arguments":{}}`) + "\n" +
				realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":7,"modelMetrics":{"m":{"usage":{"inputTokens":100,"outputTokens":20}}}}`) + "\n"
		require.NoError(t, os.WriteFile(filepath.Join(sessionDir, "events.jsonl"),
			[]byte(eventsContent), 0644))

		// Also create a .log file that would give different metrics if parsed
		require.NoError(t, os.WriteFile(filepath.Join(dir, "agent-stdio.log"),
			[]byte("some log content without metrics"), 0644))

		metrics, err := extractLogMetrics(dir, false)
		require.NoError(t, err, "extractLogMetrics should not error")

		// Should use events.jsonl values: turns=1, tokenUsage=120 (100+20 from modelMetrics)
		assert.Equal(t, 1, metrics.Turns, "turns should come from events.jsonl")
		assert.Equal(t, 120, metrics.TokenUsage, "token usage should come from modelMetrics in events.jsonl")
	})

	t.Run("falls back to log file walk when events.jsonl absent", func(t *testing.T) {
		dir := t.TempDir()

		// Write aw_info.json for copilot engine
		require.NoError(t, os.WriteFile(filepath.Join(dir, "aw_info.json"),
			[]byte(`{"engine_id":"copilot"}`), 0644))

		// No events.jsonl – only a log file with parseable content
		logContent := `2025-09-26T11:13:11.798Z [DEBUG] Starting Copilot CLI
2025-09-26T11:13:12.575Z [DEBUG] data:
2025-09-26T11:13:12.575Z [DEBUG] {
2025-09-26T11:13:12.575Z [DEBUG]   "choices": [{"message": {"role": "assistant", "content": null, "tool_calls": []}}],
2025-09-26T11:13:12.575Z [DEBUG]   "usage": {"prompt_tokens": 1000, "completion_tokens": 50, "total_tokens": 1050}
2025-09-26T11:13:12.575Z [DEBUG] }
`
		require.NoError(t, os.WriteFile(filepath.Join(dir, "process-123.log"),
			[]byte(logContent), 0644))

		metrics, err := extractLogMetrics(dir, false)
		require.NoError(t, err, "extractLogMetrics should not error")

		// Should fall back to log parsing and find at least 1 turn
		assert.GreaterOrEqual(t, metrics.Turns, 1, "should detect at least one turn from log file")
	})
}

// TestParseEventsJSONLFile_TBT verifies that Time Between Turns is computed
// correctly from per-turn timestamps embedded in user.message events.
func TestParseEventsJSONLFile_TBT(t *testing.T) {
	// Helper that produces an events.jsonl line with a specific RFC3339 timestamp.
	lineWithTimestamp := func(eventType, dataJSON, timestamp string) string {
		return `{"type":"` + eventType + `","data":` + dataJSON + `,"id":"test-id","timestamp":"` + timestamp + `"}`
	}

	t.Run("computes avg and max TBT from multi-turn timestamps", func(t *testing.T) {
		// Turn 1 at T+0s, Turn 2 at T+30s, Turn 3 at T+90s → intervals: 30s, 60s → avg 45s, max 60s
		content := lineWithTimestamp("session.start", `{"sessionId":"s1","copilotVersion":"1.0.0"}`, "2026-01-01T10:00:00Z") + "\n" +
			lineWithTimestamp("user.message", `{"content":"turn 1"}`, "2026-01-01T10:00:00Z") + "\n" +
			lineWithTimestamp("user.message", `{"content":"turn 2"}`, "2026-01-01T10:00:30Z") + "\n" +
			lineWithTimestamp("user.message", `{"content":"turn 3"}`, "2026-01-01T10:01:30Z") + "\n" +
			lineWithTimestamp("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":3,"modelMetrics":{"m":{"usage":{"inputTokens":100,"outputTokens":10}}}}`, "2026-01-01T10:02:00Z") + "\n"

		dir := t.TempDir()
		eventsPath := filepath.Join(dir, "events.jsonl")
		require.NoError(t, os.WriteFile(eventsPath, []byte(content), 0644))

		metrics, err := parseEventsJSONLFile(eventsPath, false)
		require.NoError(t, err, "should parse without error")

		assert.Equal(t, 3, metrics.Turns, "should detect 3 turns")
		assert.Equal(t, 45*time.Second, metrics.AvgTimeBetweenTurns, "avg TBT should be 45s")
		assert.Equal(t, 60*time.Second, metrics.MaxTimeBetweenTurns, "max TBT should be 60s")
	})

	t.Run("no TBT when only one turn", func(t *testing.T) {
		content := lineWithTimestamp("user.message", `{"content":"single turn"}`, "2026-01-01T10:00:00Z") + "\n" +
			lineWithTimestamp("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":1,"modelMetrics":{"m":{"usage":{"inputTokens":50,"outputTokens":5}}}}`, "2026-01-01T10:01:00Z") + "\n"

		dir := t.TempDir()
		eventsPath := filepath.Join(dir, "events.jsonl")
		require.NoError(t, os.WriteFile(eventsPath, []byte(content), 0644))

		metrics, err := parseEventsJSONLFile(eventsPath, false)
		require.NoError(t, err, "should parse without error")

		assert.Equal(t, 1, metrics.Turns, "should detect 1 turn")
		assert.Zero(t, metrics.AvgTimeBetweenTurns, "no TBT with a single turn")
		assert.Zero(t, metrics.MaxTimeBetweenTurns, "no TBT with a single turn")
	})

	t.Run("no TBT when all timestamps are identical", func(t *testing.T) {
		// Use realFormatEventsLine which always uses the same timestamp — no intervals.
		content := realFormatEventsLine("user.message", `{"content":"turn 1"}`) + "\n" +
			realFormatEventsLine("user.message", `{"content":"turn 2"}`) + "\n" +
			realFormatEventsLine("session.shutdown", `{"shutdownType":"routine","totalPremiumRequests":2,"modelMetrics":{"m":{"usage":{"inputTokens":50,"outputTokens":5}}}}`) + "\n"

		dir := t.TempDir()
		eventsPath := filepath.Join(dir, "events.jsonl")
		require.NoError(t, os.WriteFile(eventsPath, []byte(content), 0644))

		metrics, err := parseEventsJSONLFile(eventsPath, false)
		require.NoError(t, err, "should parse without error")

		assert.Equal(t, 2, metrics.Turns, "should detect 2 turns")
		// All user.message events share the same timestamp → interval is 0 → TBT stays zero.
		assert.Zero(t, metrics.AvgTimeBetweenTurns, "TBT should be zero when all timestamps are identical")
	})
}

