13	type ObservabilityInsight struct {
14		Category string `json:"category"`
15		Severity string `json:"severity"`
16		Title    string `json:"title"`
17		Summary  string `json:"summary"`
18		Evidence string `json:"evidence,omitempty"`
19	}
